// backend/Services/ChatService/ChatService.Api/ChatService.Api.csproj:
//
//   <ItemGroup>
//     <InternalsVisibleTo Include="ChatService.IntegrationTests" />
//   </ItemGroup>
//
// Without this, the implicit Program class generated by top-level statements
// is internal and not accessible to this test project.
